[GRAPH] imapclient.imap_utf7.decode:
def decode(s: Union[bytes, str]) -> str:
    if not isinstance(s, bytes):
        return s

    res = []
    b64_buffer = bytearray()
    for c in s:
        if c == AMPERSAND_ORD and not b64_buffer:
            b64_buffer.append(c)
        elif c == DASH_ORD and b64_buffer:
            if len(b64_buffer) == 1:
                res.append("&")
            else:
                res.append(base64_utf7_decode(b64_buffer[1:]))
            b64_buffer = bytearray()
        elif b64_buffer:
            b64_buffer.append(c)
        else:
            res.append(chr(c))

    if b64_buffer:
        res.append(base64_utf7_decode(b64_buffer[1:]))

    return "".join(res)


[GRAPH] imapclient.imap_utf7.encode:
def encode(s: Union[str, bytes]) -> bytes:
    if not isinstance(s, str):
        return s

    res = bytearray()

    b64_buffer: List[str] = []

    def consume_b64_buffer(buf: List[str]) -> None:
        if buf:
            res.extend(b"&" + base64_utf7_encode(buf) + b"-")
            del buf[:]

    for c in s:
        o = ord(c)
        if 0x20 <= o <= 0x7E:
            consume_b64_buffer(b64_buffer)
            if o == 0x26:  # & = 0x26
                res.extend(b"&-")
            else:
                res.append(o)

        else:
            b64_buffer.append(c)

    consume_b64_buffer(b64_buffer)

    return bytes(res)


